import React, { useCallback, useMemo, useState } from 'react';
import { LinErpListFilterBar, Select, dispatchAppToast } from '@linm-soft-org/linm-web-common-components';
import { useAppDispatch } from '../../../store/hooks';
import { analyticsService } from '../../../services/analytics/analyticsService';
import { formatVnd } from '../../../utils/formatters';
import { MONTH_OPTIONS, YEAR_OPTIONS } from '../../../utils/exportExcel';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import reportStyles from '../../../styles/erpReportPage.module.css';
import type { DepreciationReportRow } from '../../../services/analytics/models';
import { AnalyticsReportShell, ReportTableWrap } from '../../../components/report';

const TEST_ID = 'erp-bao-cao-tscd';
const PAGE_ID = 'baocao-tscd';

const BaoCaoTscdPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const now = new Date();
  const [month, setMonth] = useState(now.getMonth() + 1);
  const [year, setYear] = useState(now.getFullYear());
  const [rows, setRows] = useState<DepreciationReportRow[]>([]);
  const [loading, setLoading] = useState(false);

  const handleLoad = useCallback(() => {
    setLoading(true);
    analyticsService
      .getDepreciationReport({ month, year })
      .then(setRows)
      .catch(err =>
        dispatchAppToast(dispatch, {
          message: getApiErrorMessage(err, 'Lỗi'),
          type: 'error',
        }),
      )
      .finally(() => setLoading(false));
  }, [month, year, dispatch]);

  const listFilters = useMemo(
    () => (
      <LinErpListFilterBar
        testIdPrefix={TEST_ID}
        onDateChange={() => {}}
        onSearch={handleLoad}
        searchAriaLabel="Xem"
        loading={loading}
        leading={(
          <>
            <div data-testid={`${TEST_ID}-field-month`}>
              <Select label="Tháng" value={String(month)} onChange={e => setMonth(Number(e.target.value))} options={MONTH_OPTIONS} size="small" />
            </div>
            <div data-testid={`${TEST_ID}-field-year`}>
              <Select label="Năm" value={String(year)} onChange={e => setYear(Number(e.target.value))} options={YEAR_OPTIONS} size="small" />
            </div>
          </>
        )}
      />
    ),
    [month, year, handleLoad, loading],
  );

  return (
    <AnalyticsReportShell
      testId={TEST_ID}
      pageId={PAGE_ID}
      title="Khấu hao TSCĐ"
      titleIconClass="fas fa-building"
      loading={loading}
      hasData={rows.length > 0}
      filters={listFilters}
      onLoad={handleLoad}
      exportPath="/assets/depreciation-report/export-excel"
      exportParams={{ month, year }}
      exportFilename={`TSCD-T${month}-${year}.xlsx`}
    >
      <ReportTableWrap testId={`${TEST_ID}-grid`}>
        <thead>
          <tr>
            <th>Mã TS</th>
            <th>Tên</th>
            <th className={reportStyles.colRight}>Nguyên giá</th>
            <th className={reportStyles.colRight}>KH kỳ</th>
            <th className={reportStyles.colRight}>LK KH</th>
            <th className={reportStyles.colRight}>Còn lại</th>
          </tr>
        </thead>
        <tbody>
          {rows.map((r, i) => (
            <tr key={i}>
              <td>{r.assetCode}</td>
              <td>{r.assetName}</td>
              <td className={reportStyles.colRight}>{formatVnd(r.originalCost)}</td>
              <td className={reportStyles.colRight}>{formatVnd(r.depreciationAmount)}</td>
              <td className={reportStyles.colRight}>{formatVnd(r.accumulatedDepreciation)}</td>
              <td className={reportStyles.colRight}>{formatVnd(r.remainingValue)}</td>
            </tr>
          ))}
        </tbody>
      </ReportTableWrap>
    </AnalyticsReportShell>
  );
};

export default BaoCaoTscdPage;
